import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import '../App.css';

function Sidebar() {
    const location = useLocation();
    const role = localStorage.getItem('role');

    // Hàm kiểm tra xem link có đang được chọn không để đổi màu
    const activeClass = (path) => location.pathname === path ? "active-link" : "";

    let menuItems = [];

    if (role === 'ADMIN') {
        menuItems = [
            { path: '/dashboard', label: 'Dashboard' },
            { path: '/departments', label: 'Quản lý Phòng ban' },
            { path: '/employees', label: 'Hồ sơ Nhân sự' },
            { path: '/contracts', label: 'Hợp đồng lao động' },
            { path: '/accounts', label: 'Quản lý Tài khoản' },
            { path: '/settings', label: 'Cấu hình hệ thống' }
        ];
    } else if (role === 'ACCOUNTANT') {
        menuItems = [
            { path: '/dashboard', label: 'Dashboard' },
            { path: '/profile', label: 'Trang cá nhân' },
            { path: '/my-attendance', label: 'Thời gian chấm công' },
            { path: '/salary', label: 'Quản lý Bảng lương' },
            { path: '/payment-history', label: 'Lịch sử Chi trả' },
            { path: '/reports', label: 'Xuất báo cáo' }
        ];
    } else {
        // Mặc định hoặc dành cho Nhân viên (TEACHER, Giảng viên, Bảo vệ...)
        menuItems = [
            { path: '/profile', label: 'Trang cá nhân' },
            { path: '/my-attendance', label: 'Chấm công cá nhân' },
            { path: '/my-salary', label: 'Tra cứu Bảng lương' },
            { path: '/my-contract', label: 'Hợp đồng cá nhân' },
            { path: '/change-password', label: 'Đổi mật khẩu' }
        ];
    }

    return (
        <div className="sidebar">
            <div className="sidebar-header">MyAdmin</div>
            <ul className="sidebar-menu">
                {menuItems.map((item, index) => (
                    <li key={index} className={activeClass(item.path)}>
                        <Link to={item.path}>{item.label}</Link>
                    </li>
                ))}
            </ul>
        </div>
    );
}

export default Sidebar;
